{"path": "02_SKILLS/dashboard_layout.json", "content": "{
  "component": {
    "id": "dashboard",
    "name": "DashboardLayout",
    "description": "Main dashboard layout with sidebar, header, and content area",
    "version": "1.0.0"
  },
  "theme": {
    "mode": "dark",
    "colors": {
      "primary": "#6366f1",
      "secondary": "#8b5cf6",
      "accent": "#06b6d4",
      "background": "#0f172a",
      "surface": "#1e293b",
      "surface_elevated": "#334155",
      "text_primary": "#f8fafc",
      "text_secondary": "#94a3b8",
      "border": "#475569"
    },
    "typography": {
      "font_family": "Inter, sans-serif",
      "font_size_base": 14,
      "font_size_heading": 24,
      "font_size_subheading": 18
    },
    "spacing": {
      "base_unit": 4,
      "sidebar_width": 240,
      "header_height": 56,
      "content_padding": 24,
      "card_padding": 16,
      "gap_small": 8,
      "gap_medium": 16,
      "gap_large": 24
    },
    "borders": {
      "radius": 8,
      "radius_small": 4,
      "radius_large": 12
    },
    "effects": {
      "shadow_enabled": true,
      "shadow_default": "0 4px 6px -1px rgba(0, 0, 0, 0.3)",
      "shadow_elevated": "0 10px 15px -3px rgba(0, 0, 0, 0.4)",
      "animations_enabled": true,
      "transition_duration": 200
    }
  },
  "layout": {
    "type": "shell",
    "structure": {
      "sidebar": {
        "width": 240,
        "position": "left",
        "collapsible": false,
        "sections": [
          {
            "id": "navigation",
            "items": [
              { "id": "home", "label": "Home", "icon": "home", "active": true },
              { "id": "markets", "label": "Markets", "icon": "chart", "active": false },
              { "id": "trading", "label": "Trading", "icon": "exchange", "active": false },
              { "id": "analytics", "label": "Analytics", "icon": "bar-chart", "active": false },
              { "id": "settings", "label": "Settings", "icon": "cog", "active": false }
            ]
          },
          {
            "id": "agents",
            "label": "Agents",
            "items": [
              { "id": "agent_alpha", "label": "Agent Alpha", "status": "active" },
              { "id": "agent_beta", "label": "Agent Beta", "status": "idle" }
            ]
          }
        ]
      },
      "header": {
        "height": 56,
        "components": [
          { "type": "breadcrumbs", "id": "breadcrumb" },
          { "type": "search", "id": "global_search", "placeholder": "Search..." },
          { "type": "notifications", "id": "notification_bell", "count": 3 },
          { "type": "user_menu", "id": "user_menu" }
        ]
      },
      "content": {
        "padding": 24,
        "max_width": null,
        "grid": {
          "columns": 12,
          "gap": 16
        }
      }
    }
  },
  "components": {
    "stat_card": {
      "id": "stat_card",
      "props": {
        "padding": 16,
        "bordered": true,
        "border_radius": 8,
        "shadow": true,
        "elevation": 2,
        "hover_elevation": 4
      },
      "structure": {
        "label": {
          "type": "text",
          "style": "text_secondary",
          "size": 14
        },
        "value": {
          "type": "number",
          "style": "text_primary",
          "size": 28,
          "weight": 600
        },
        "trend": {
          "type": "indicator",
          "positive_color": "#22c55e",
          "negative_color": "#ef4444"
        }
      }
    },
    "chart_card": {
      "id": "chart_card",
      "props": {
        "padding": 16,
        "bordered": true,
        "border_radius": 8,
        "shadow": true
      },
      "structure": {
        "header": {
          "title": "string",
          "actions": ["refresh", "export"]
        },
        "body": {
          "type": "chart",
          "chart_types": ["line", "bar", "candlestick"]
        }
      }
    },
    "data_table": {
      "id": "data_table",
      "props": {
        "bordered": true,
        "striped": true,
        "hoverable": true
      },
      "features": {
        "sorting": true,
        "filtering": true,
        "pagination": true,
        "page_size": 10
      }
    },
    "action_button": {
      "primary": {
        "style": "filled",
        "hover_effects": true,
        "border_radius": 8,
        "padding": "12px 24px"
      },
      "secondary": {
        "style": "outline",
        "hover_effects": true,
        "border_radius": 8
      }
    }
  },
  "responsive": {
    "breakpoints": {
      "mobile": 640,
      "tablet": 768,
      "desktop": 1024
    },
    "layouts": {
      "mobile": {
        "sidebar": { "hidden": true, "hamburger_menu": true },
        "header": { "height": 48 },
        "content": { "padding": 16 }
      },
      "tablet": {
        "sidebar": { "collapsed": true, "width": 64 },
        "header": { "height": 56 },
        "content": { "padding": 20 }
      },
      "desktop": {
        "sidebar": { "expanded": true, "width": 240 },
        "header": { "height": 56 },
        "content": { "padding": 24 }
      }
    }
  },
  "animations": {
    "page_transition": {
      "type": "fade",
      "duration": 200
    },
    "sidebar_toggle": {
      "type": "slide",
      "duration": 200
    },
    "card_hover": {
      "type": "scale",
      "duration": 150
    },
    "button_press": {
      "type": "scale",
      "scale": 0.98,
      "duration": 100
    }
  }
}
"

